%d1%96%d2%91%d0%b3%c2%a7%d0%b1%d0%b2%d2%91%d0%b3-17-2','','','2024-10-29 11:38:43','2024-10-29 11:38:43','',125,'http://212.67.11.114/app/uploads/2024/10/ПаЃ®ІҐЃ§бвҐЃ-17.jpg',0,'attachment','image/jpeg',0),(273,1,'2024-10-29 11:38:51','2024-10-29 11:38:51','','ПаЃ®ІҐЃ§бвҐЃ (18)','','inherit','open','closed','','%d0%bf%d0%b0%d0%b3%d1%96%d2%91%d0%b3%c2%a7%d0%b1%d0%b2%d2%91%d0%b3-18-2','','','2024-10-29 11:38:51','2024-10-29 11:38:51','',125,'http://212.67.11.114/app/uploads/2024/10/ПаЃ®ІҐЃ§бвҐЃ-18.jpg',0,'attachment','image/jpeg',0),(276,1,'2024-10-31 16:24:11','2024-10-31 16:24:11','','П†в•≠в','','inherit','open','closed','','%d0%bf%e2%80%a0%d0%b2%e2%89%a0%d0%b2','','','2024-10-31 16:24:11','2024-10-31 16:24:11','',155,'http://212.67.11.114/app/uploads/2024/10/П†в•≠в.pdf',0,'attachment','application/pdf',0),(277,1,'2024-10-31 16:24:45','2024-10-31 16:24:45','','2024-10-16 21.04.06','','inherit','open','closed','','2024-10-16-21-04-06-8','','','2024-10-31 16:24:57','2024-10-31 16:24:57','',155,'http://212.67.11.114/app/uploads/2024/10/2024-10-16-21.04.06.jpg',0,'attachment','image/jpeg',0),(278,1,'2024-10-31 16:24:47','2024-10-31 16:24:47','','2024-10-16 21.04.06','','inherit','open','closed','','2024-10-16-21-04-06-9','','','2024-10-31 16:24:47','2024-10-31 16:24:47','',155,'http://212.67.11.114/app/uploads/2024/10/2024-10-16-21.04.06-1.jpg',0,'attachment','image/jpeg',0),(279,1,'2024-10-31 16:24:51','2024-10-31 16:24:51','','2024-10-16 21.04.06','','inherit','open','closed','','2024-10-16-21-04-06-10','','','2024-10-31 16:24:51','2024-10-31 16:24:51','',155,'http://212.67.11.114/app/uploads/2024/10/2024-10-16-21.04.06-2.jpg',0,'attachment','image/jpeg',0),(280,1,'2024-10-31 16:24:52','2024-10-31 16:24:52','','2024-10-16 21.04.06','','inherit','open','closed','','2024-10-16-21-04-06-11','','','2024-10-31 16:25:04','2024-10-31 16:25:04','',155,'http://212.67.11.114/app/uploads/2024/10/2024-10-16-21.04.06-3.jpg',0,'attachment','image/jpeg',0),(281,1,'2024-10-31 16:25:07','2024-10-31 16:25:07','<p class=\"p1\">Компания ООО «ЗАМАН» является экспертом в производстве<b> мобильных скважинных компрессорных установок (МСКУ)</b> – эффективного решения для устранения повышенного содержания газа в затрубном пространстве нефтяных скважин при добыче пластовой жидкости.</p>\r\n<p class=\"p1\">Мы предлагаем высококачественный продукт, который отличается долговечностью и простотой в эксплуатации. Гарантируем быстрое производство и поставку, что позволит оперативно внедрить нашу установку и получить от нее положительный эффект, а также предоставляем качественную техническую поддержку на протяжении всего срока ее эксплуатации.</p>\r\n<p class=\"p1\">МСКУ состоит из многоступенчатого компрессора с электрическим приводом, а также технологической линии, размещенных в блоке-укрытии. Технологическая линия включает в себя запорно-регулируемую арматуру, устройство подготовки газа и систему контроля параметрами. Автоматическая работа осуществляется станцией управления, обеспечивая не только мониторинг эксплуатации установки, но и безопасность технологического процесса на объекте.</p>\r\n<p class=\"p1\">Установка легко подключается к различной затрубной арматуре скважин с любым насосным оборудованием (ШГН, УЭЦН, УЭВН), что делает ее универсальным и удобным решением для различных типов скважин. Закачка газа производится в нефтесборный коллектор. Фундамент не требуется.<span class=\"Apple-converted-space\"> </span></p>\r\n<p class=\"p1\">Благодаря возможности оформления МСКУ в соответствии с корпоративным стилем Заказчика Вы получите уникальное оборудование.</p>\r\n<p class=\"p1\">Свяжитесь с нами для получения подробной информации, и мы с удовольствием поможем Вам выбрать оптимальное решение, которое позволит повысить эффективность эксплуатации скважин, увеличить добычу нефти и газа и исключить выбросы вредных веществ в окружающую среду!</p>','Мобильные скважинные компрессорные установки (МСКУ)','','inherit','closed','closed','','155-revision-v1','','','2024-10-31 16:25:07','2024-10-31 16:25:07','',155,'http://212.67.11.114/uncategorized/155-revision-v1/',0,'revision','',0),(283,1,'2024-10-31 16:26:33','2024-10-31 16:26:33','','5','','inherit','open','closed','','5-6','','','2024-10-31 16:36:03','2024-10-31 16:36:03','',155,'http://212.67.11.114/app/uploads/2024/10/5.jpg',0,'attachment','image/jpeg',0),(284,1,'2024-10-31 16:26:44','2024-10-31 16:26:44','','4','','inherit','open','closed','','4-6','','','2024-10-31 16:26:44','2024-10-31 16:26:44','',155,'http://212.67.11.114/app/uploads/2024/10/4.jpg',0,'attachment','image/jpeg',0),(285,1,'2024-10-31 16:27:01','2024-10-31 16:27:01','','3','','inherit','open','closed','','3-6','','','2024-10-31 16:27:01','2024-10-31 16:27:01','',155,'http://212.67.11.114/app/uploads/2024/10/3.jpg',0,'attachment','image/jpeg',0),(286,1,'2024-10-31 16:35:50','2024-10-31 16:35:50','','1','','inherit','open','closed','','1-6','','','2024-10-31 16:35:50','2024-10-31 16:35:50','',155,'http://212.67.11.114/app/uploads/2024/10/1.jpg',0,'attachment','image/jpeg',0),(287,1,'2024-10-31 16:35:58','2024-10-31 16:35:58','','2','','inherit','open','closed','','2-6','','','2024-10-31 16:35:58','2024-10-31 16:35:58','',155,'http://212.67.11.114/app/uploads/2024/10/2.jpg',0,'attachment','image/jpeg',0),(288,1,'2024-10-31 16:36:08','2024-10-31 16:36:08','<p class=\"p1\">Компания ООО «ЗАМАН» является экспертом в производстве<b> мобильных скважинных компрессорных установок (МСКУ)</b> – эффективного решения для устранения повышенного содержания газа в затрубном пространстве нефтяных скважин при добыче пластовой жидкости.</p>\r\n<p class=\"p1\">Мы предлагаем высококачественный продукт, который отличается долговечностью и простотой в эксплуатации. Гарантируем быстрое производство и поставку, что позволит оперативно внедрить нашу установку и получить от нее положительный эффект, а также предоставляем качественную техническую поддержку на протяжении всего срока ее эксплуатации.</p>\r\n<p class=\"p1\">МСКУ состоит из многоступенчатого компрессора с электрическим приводом, а также технологической линии, размещенных в блоке-укрытии. Технологическая линия включает в себя запорно-регулируемую арматуру, устройство подготовки газа и систему контроля параметрами. Автоматическая работа осуществляется станцией управления, обеспечивая не только мониторинг эксплуатации установки, но и безопасность технологического процесса на объекте.</p>\r\n<p class=\"p1\">Установка легко подключается к различной затрубной арматуре скважин с любым насосным оборудованием (ШГН, УЭЦН, УЭВН), что делает ее универсальным и удобным решением для различных типов скважин. Закачка газа производится в нефтесборный коллектор. Фундамент не требуется.<span class=\"Apple-converted-space\"> </span></p>\r\n<p class=\"p1\">Благодаря возможности оформления МСКУ в соответствии с корпоративным стилем Заказчика Вы получите уникальное оборудование.</p>\r\n<p class=\"p1\">Свяжитесь с нами для получения подробной информации, и мы с удовольствием поможем Вам выбрать оптимальное решение, которое позволит повысить эффективность эксплуатации скважин, увеличить добычу нефти и газа и исключить выбросы вредных веществ в окружающую среду!</p>','Мобильные скважинные компрессорные установки (МСКУ)','','inherit','closed','closed','','155-revision-v1','','','2024-10-31 16:36:08','2024-10-31 16:36:08','',155,'http://212.67.11.114/uncategorized/155-revision-v1/',0,'revision','',0),(289,1,'2024-10-31 16:37:20','2024-10-31 16:37:20','','5','','inherit','open','closed','','5-7','','','2024-10-31 16:37:50','2024-10-31 16:37:50','',52,'http://212.67.11.114/app/uploads/2024/10/5-1.jpg',0,'attachment','image/jpeg',0),(290,1,'2024-10-31 16:37:28','2024-10-31 16:37:28','','4','','inherit','open','closed','','4-7','','','2024-10-31 16:37:28','2024-10-31 16:37:28','',52,'http://212.67.11.114/app/uploads/2024/10/4-1.jpg',0,'attachment','image/jpeg',0),(291,1,'2024-10-31 16:37:33','2024-10-31 16:37:33','','3','','inherit','open','closed','','3-7','','','2024-10-31 16:37:33','2024-10-31 16:37:33','',52,'http://212.67.11.114/app/uploads/2024/10/3-1.jpg',0,'attachment','image/jpeg',0),(292,1,'2024-10-31 16:37:37','2024-10-31 16:37:37','','2','','inherit','open','closed','','2-7','','','2024-10-31 16:37:37','2024-10-31 16:37:37','',52,'http://212.67.11.114/app/uploads/2024/10/2-1.jpg',0,'attachment','image/jpeg',0),(293,1,'2024-10-31 16:37:44','2024-10-31 16:37:44','','1','','inherit','open','closed','','1-7','','','2024-10-31 16:37:44','2024-10-31 16:37:44','',52,'http://212.67.11.114/app/uploads/2024/10/1-1.jpg',0,'attachment','image/jpeg',0),(294,1,'2024-10-31 16:37:52','2024-10-31 16:37:52','<p class=\"p1\">ОБЩЕСТВО С ОГРАНИЧЕННОЙ ОТВЕТСТВЕННОСТЬЮ «ЗАМАН» основано в 2012 году в городе Альметьевск, как машиностроительная сервисная компания.</p>\r\n<p class=\"p1\">Основными видами деятельности являются производство и сервис нефтепромыслового оборудования.<span class=\"Apple-converted-space\"> </span></p>\r\n<p class=\"p1\">Компания обладает производственной базой, включающей в себя офис (300 м<span class=\"s1\"><sup>2</sup></span>) и сборочный цех (600 м<span class=\"s1\"><sup>2</sup></span>), оснащенный современной техникой, профессиональными инструментами и оборудованием, позволяющими производить качественную серийную продукцию, а также нестандартное оборудование.</p>\r\n<p class=\"p1\">Циклом сотрудничества с Заказчиками является: 1. обработка заявки, 2. проектирование и техническое согласование, 3. заключение договора, 4. производство, 5. сдача проекта, ввод в эксплуатацию, 6. сервис.</p>\r\n<p class=\"p1\">Основной ассортимент продукции компании включает в себя компрессорные установки и станции для работы с любыми типами газов. Оборудование и агрегаты комплектуются как в открытом, так и в закрытом исполнении, учитывая потребности Заказчиков. Используются комплектующие от ведущих производителей, преимущественно из России и других дружественных стран, что обеспечивает высокую надежность и сокращает сроки реализации проектов. По желанию Заказчиков, могут быть применены импортные комплектующие.</p>\r\n<p class=\"p1\">В компании осуществляется производство блок-боксов, блоков укрытий, аппаратурных блоков и модульных мобильных зданий, собранных из металлоконструкций и сэндвич-панелей.<span class=\"Apple-converted-space\"> </span></p>\r\n<p class=\"p1\">Разрабатываются АСУ ТП, сборка НКУ и сервис.<span class=\"Apple-converted-space\"> </span></p>\r\n<p class=\"p1\">Осуществляется производство насосных станций, ряда дозировочного оборудования химических реагентов (БДР, УДХР и др.) для нефтедобывающих предприятий по принципу пэкиджирования.<span class=\"Apple-converted-space\"> </span></p>\r\n<p class=\"p1\">Кроме того, осуществлены проекты производства и поставок блоков гребенок (БГ). <span class=\"Apple-converted-space\"> </span></p>\r\n<p class=\"p1\">Специалисты сервисной службы имеют опыт технического обслуживания и капитального ремонта компрессорного и насосного оборудования любых производителей, включая импортных.</p>\r\n<p class=\"p1\">В ООО «ЗАМАН» имеется консигнационный склад с комплектующими серийной продукции, что позволяет осуществлять производство НПО в короткие сроки, а сервис сделать максимально оперативным.</p>\r\n&nbsp;\r\n<h2 class=\"p1\">Задачи ООО «ЗАМАН»:</h2>\r\n<ul>\r\n 	<li>Превосходить ожидания наших партнеров, путем предоставления высококачественной продукции и первоклассного сервиса «под ключ», соответствующего современным научным и экономическим подходам и требованиям;</li>\r\n 	<li>Быть лидером в секторе машиностроения для нефтегазовой отрасли, внедряя инновации и технологии для оптимизации времени и ресурсов наших партнеров.</li>\r\n</ul>\r\n&nbsp;\r\n<h2 class=\"p1\"><b>ЗАМАН - ВРЕМЯ СОЗИДАТЬ БУДУЩЕЕ!</b></h2>\r\n<p class=\"p1\"><b>*</b><i> в переводе с татарского языка «заман» - «время», «эпоха».</i></p>','О компании','','inherit','closed','closed','','52-revision-v1','','','2024-10-31 16:37:52','2024-10-31 16:37:52','',52,'http://212.67.11.114/uncategorized/52-revision-v1/',0,'revision','',0),(295,1,'2024-10-31 16:40:01','2024-10-31 16:40:01','','msg-508181174-76856','','inherit','open','closed','','msg-508181174-76856-3','','','2024-10-31 16:40:01','2024-10-31 16:40:01','',97,'http://212.67.11.114/app/uploads/2024/10/msg-508181174-76856.jpg',0,'attachment','image/jpeg',0),(296,1,'2024-10-31 16:40:02','2024-10-31 16:40:02','','msg-508181174-76849','','inherit','open','closed','','msg-508181174-76849-3','','','2024-10-31 16:40:02','2024-10-31 16:40:02','',97,'http://212.67.11.114/app/uploads/2024/10/msg-508181174-76849.jpg',0,'attachment','image/jpeg',0),(297,1,'2024-10-31 16:40:04','2024-10-31 16:40:04','','IMG_20240307_101156','','inherit','open','closed','','img_20240307_101156-3','','','2024-10-31 16:40:04','2024-10-31 16:40:04','',97,'http://212.67.11.114/app/uploads/2024/10/IMG_20240307_101156.jpg',0,'attachment','image/jpeg',0),(298,1,'2024-10-31 16:40:09','2024-10-31 16:40:09','','DSC04024','','inherit','open','closed','','dsc04024-3','','','2024-10-31 16:40:18','2024-10-31 16:40:18','',97,'http://212.67.11.114/app/uploads/2024/10/DSC04024.jpg',0,'attachment','image/jpeg',0),(299,1,'2024-10-31 16:40:23','2024-10-31 16:40:23','Сегодняшний день был похож на настоящую сказку, которую нам подарили наши мужчины ООО \"ЗАМАН\"!\r\n\r\nКаждую из нас забрали из дома, офис был украшен цветами, шарами и лепестками роз. Нас пригласили за безумно красиво украшенный стол, где был праздничный завтрак. Гусары наливали шампанское, мы играли в игры и вкусно кушали. После этого нас отвезли на фотосессию, где тоже был накрыт фуршет с вкусняшками. А завершился этот незабываемый день в ресторане со вкусным ужином и увлекательной программой.\r\n\r\nМы, девушки из команды, выражаем огромную благодарность нашим замечательным коллегам за эту волшебную сказку, которую они устроили для нас в честь 8 марта! Спасибо за Ваше внимание и заботу, за то, что делаете нашу жизнь ярче и волшебнее! Мы СЧАСТЛИВЫЫЫ!»','Поздравили наших прекрасных девушек с Международным Женским Днем!','','inherit','closed','closed','','97-revision-v1','','','2024-10-31 16:40:23','2024-10-31 16:40:23','',97,'http://212.67.11.114/uncategorized/97-revision-v1/',0,'revision','',0),(300,1,'2024-10-31 16:41:33','2024-10-31 16:41:33','','ПаЃ®ІҐЃ§бвҐЃ (9)','','inherit','open','closed','','%d0%bf%d0%b0%d0%b3%d1%96%d2%91%d0%b3%c2%a7%d0%b1%d0%b2%d2%91%d0%b3-9-3','','','2024-10-31 16:44:07','2024-10-31 16:44:07','',125,'http://212.67.11.114/app/uploads/2024/10/ПаЃ®ІҐЃ§бвҐЃ-9.jpg',0,'attachment','image/jpeg',0),(301,1,'2024-10-31 16:41:40','2024-10-31 16:41:40','','ПаЃ®ІҐЃ§бвҐЃ (8)','','inherit','open','closed','','%d0%bf%d0%b0%d0%b3%d1%96%d2%91%d0%b3%c2%a7%d0%b1%d0%b2%d2%91%d0%b3-8-3','','','2024-10-31 16:41:40','2024-10-31 16:41:40','',125,'http://212.67.11.114/app/uploads/2024/10/ПаЃ®ІҐЃ§бвҐЃ-8.jpg',0,'attachment','image/jpeg',0),(302,1,'2024-10-31 16:41:48','2024-10-31 16:41:48','','ПаЃ®ІҐЃ§бвҐЃ (7)','','inherit','open','closed','','%d0%bf%d0%b0%d0%b3%d1%96%d2%91%d0%b3%c2%a7%d0%b1%d0%b2%d2%91%d0%b3-7-3','','','2024-10-31 16:41:48','2024-10-31 16:41:48','',125,'http://212.67.11.114/app/uploads/2024/10/ПаЃ®ІҐЃ§бвҐЃ-7.jpg',0,'attachment','image/jpeg',0),(303,1,'2024-10-31 16:41:57','2024-10-31 16:41:57','','ПаЃ®ІҐЃ§бвҐЃ (6)','','inherit','open','closed','','%d0%bf%d0%b0%d0%b3%d1%96%d2%91%d0%b3%c2%a7%d0%b1%d0%b2%d2%91%d0%b3-6-3','','','2024-10-31 16:41:57','2024-10-31 16:41:57','',125,'http://212.67.11.114/app/uploads/2024/10/ПаЃ®ІҐЃ§бвҐЃ-6.jpg',0,'attachment','image/jpeg',0),(304,1,'2024-10-31 16:42:05','2024-10-31 16:42:05','','ПаЃ®ІҐЃ§бвҐЃ (5)','','inherit','open','closed','','%d0%bf%d0%b0%d0%b3%d1%96%d2%91%d0%b3%c2%a7%d0%b1%d0%b2%d2%91%d0%b3-5-3','','','2024-10-31 16:42:05','2024-10-31 16:42:05','',125,'http://212.67.11.114/app/uploads/2024/10/ПаЃ®ІҐЃ§бвҐЃ-5.jpg',0,'attachment','image/jpeg',0),(305,1,'2024-10-31 16:42:16','2024-10-31 16:42:16','','ПаЃ®ІҐЃ§бвҐЃ (4)','','inherit','ope