2%89%a0%e2%80%a0-%d0%b3%d0%ba%d0%b2%e2%80%a0%d0%b5-%d1%96%d1%92%e2%80%a0-10','','','2024-11-18 15:37:29','2024-11-18 15:37:29','',557,'https://zamman.ru/app/uploads/2024/11/Р†°Ѓв†-≠†-Ѓ°к•™в†е-І®ђ†-10.jpg',0,'attachment','image/jpeg',0),(774,1,'2024-11-18 15:37:46','2024-11-18 15:37:46','','Р†°Ѓв† ≠† Ѓ°к•™в†е І®ђ† (1)','','inherit','open','closed','','%d1%80%e2%80%a0%d0%b3%d0%b2%e2%80%a0-%e2%89%a0%e2%80%a0-%d0%b3%d0%ba%d0%b2%e2%80%a0%d0%b5-%d1%96%d1%92%e2%80%a0-1','','','2024-11-18 15:37:46','2024-11-18 15:37:46','',557,'https://zamman.ru/app/uploads/2024/11/Р†°Ѓв†-≠†-Ѓ°к•™в†е-І®ђ†-1.jpg',0,'attachment','image/jpeg',0),(775,1,'2024-11-18 15:37:59','2024-11-18 15:37:59','','Работа на объектах','','inherit','closed','closed','','557-revision-v1','','','2024-11-18 15:37:59','2024-11-18 15:37:59','',557,'https://zamman.ru/uncategorized/557-revision-v1/',0,'revision','',0),(776,1,'2024-11-18 15:38:51','2024-11-18 15:38:51','','С_3','','inherit','open','closed','','%d1%81_3-2','','','2024-11-18 15:38:51','2024-11-18 15:38:51','',155,'https://zamman.ru/app/uploads/2024/10/С_3.jpg',0,'attachment','image/jpeg',0),(777,1,'2024-11-18 15:38:57','2024-11-18 15:38:57','','С_2','','inherit','open','closed','','%d1%81_2-4','','','2024-11-18 15:38:57','2024-11-18 15:38:57','',155,'https://zamman.ru/app/uploads/2024/10/С_2.jpg',0,'attachment','image/jpeg',0),(778,1,'2024-11-18 15:39:25','2024-11-18 15:39:25','','С_1','','inherit','open','closed','','%d1%81_1-5','','','2024-11-18 15:39:25','2024-11-18 15:39:25','',155,'https://zamman.ru/app/uploads/2024/10/С_1.jpg',0,'attachment','image/jpeg',0),(779,1,'2024-11-18 15:40:16','2024-11-18 15:40:16','','Отзыв 4','','inherit','open','closed','','%d0%be%d1%82%d0%b7%d1%8b%d0%b2-4-3','','','2024-11-18 15:40:16','2024-11-18 15:40:16','',155,'https://zamman.ru/app/uploads/2024/10/Отзыв-4.jpg',0,'attachment','image/jpeg',0),(780,1,'2024-11-18 15:40:17','2024-11-18 15:40:17','','Отзыв 3','','inherit','open','closed','','%d0%be%d1%82%d0%b7%d1%8b%d0%b2-3-3','','','2024-11-18 15:40:17','2024-11-18 15:40:17','',155,'https://zamman.ru/app/uploads/2024/10/Отзыв-3.jpg',0,'attachment','image/jpeg',0),(781,1,'2024-11-18 15:40:18','2024-11-18 15:40:18','','Отзыв 2','','inherit','open','closed','','%d0%be%d1%82%d0%b7%d1%8b%d0%b2-2-3','','','2024-11-18 15:40:18','2024-11-18 15:40:18','',155,'https://zamman.ru/app/uploads/2024/10/Отзыв-2.jpg',0,'attachment','image/jpeg',0),(782,1,'2024-11-18 15:40:18','2024-11-18 15:40:18','','Отзыв 1','','inherit','open','closed','','%d0%be%d1%82%d0%b7%d1%8b%d0%b2-1-3','','','2024-11-18 15:40:18','2024-11-18 15:40:18','',155,'https://zamman.ru/app/uploads/2024/10/Отзыв-1.jpg',0,'attachment','image/jpeg',0),(783,1,'2024-11-18 15:40:28','2024-11-18 15:40:28','<p class=\"p1\">Компания ООО «ЗАМАН» является экспертом в производстве<b> мобильных скважинных компрессорных установок (МСКУ)</b> – эффективного решения для устранения повышенного содержания газа в затрубном пространстве нефтяных скважин при добыче пластовой жидкости.</p>\r\n<p class=\"p1\">Мы предлагаем высококачественный продукт, который отличается долговечностью и простотой в эксплуатации. Гарантируем быстрое производство и поставку, что позволит оперативно внедрить нашу установку и получить от нее положительный эффект, а также предоставляем качественную техническую поддержку на протяжении всего срока ее эксплуатации.</p>\r\n<p class=\"p1\">МСКУ состоит из многоступенчатого компрессора с электрическим приводом, а также технологической линии, размещенных в блоке-укрытии. Технологическая линия включает в себя запорно-регулируемую арматуру, устройство подготовки газа и систему контроля параметрами. Автоматическая работа осуществляется станцией управления, обеспечивая не только мониторинг эксплуатации установки, но и безопасность технологического процесса на объекте.</p>\r\n<p class=\"p1\">Установка легко подключается к различной затрубной арматуре скважин с любым насосным оборудованием (ШГН, УЭЦН, УЭВН), что делает ее универсальным и удобным решением для различных типов скважин. Закачка газа производится в нефтесборный коллектор. Фундамент не требуется.<span class=\"Apple-converted-space\"> </span></p>\r\n<p class=\"p1\">Благодаря возможности оформления МСКУ в соответствии с корпоративным стилем Заказчика Вы получите уникальное оборудование.</p>\r\n<p class=\"p1\">Свяжитесь с нами для получения подробной информации, и мы с удовольствием поможем Вам выбрать оптимальное решение, которое позволит повысить эффективность эксплуатации скважин, увеличить добычу нефти и газа и исключить выбросы вредных веществ в окружающую среду!</p>','Мобильные скважинные компрессорные установки (МСКУ)','','inherit','closed','closed','','155-revision-v1','','','2024-11-18 15:40:28','2024-11-18 15:40:28','',155,'https://zamman.ru/uncategorized/155-revision-v1/',0,'revision','',0),(784,1,'2024-11-18 15:41:20','2024-11-18 15:41:20','','С_2 (1)','','inherit','open','closed','','%d1%81_2-1','','','2024-11-18 15:41:20','2024-11-18 15:41:20','',360,'https://zamman.ru/app/uploads/2024/11/С_2-1.jpg',0,'attachment','image/jpeg',0),(785,1,'2024-11-18 15:41:22','2024-11-18 15:41:22','','С_1 (1)','','inherit','open','closed','','%d1%81_1-1','','','2024-11-18 15:41:22','2024-11-18 15:41:22','',360,'https://zamman.ru/app/uploads/2024/11/С_1-1.jpg',0,'attachment','image/jpeg',0),(786,1,'2024-11-18 15:41:33','2024-11-18 15:41:33','<p class=\"p1\">Компания ООО «ЗАМАН» обладает опытом в области пэкиджирования <b>насосных станций (НС)</b>, как компактных одноблочных, так и модульных.</p>\r\n<p class=\"p1\">Насосные станции нашего производства уже доказали свою надежность и высокую эффективность в нефтегазовых и промышленных предприятиях. Поэтому мы с уверенностью гарантируем Вам их долговечность и безотказную работу.<span class=\"Apple-converted-space\"> </span></p>\r\n<p class=\"p4\">В ассортименте представлены различные виды станций с насосами горизонтальных центробежных агрегатов (ГЦНА), плунжерных (ПНА) и центробежных секционных (ЦНС).<span class=\"Apple-converted-space\"> </span></p>\r\n<p class=\"p1\">Мы готовы реализовать проекты, соответствующие требованиям технического задания наших Заказчиков и в соответствии их специфики. <span class=\"Apple-converted-space\"> </span></p>\r\n<p class=\"p4\">Свяжитесь с нами, чтобы получить консультацию по необходимому насосному оборудованию, узнать технические характеристики реализованных проектов и обсудить условия сотрудничества!</p>','Насосные станции (НС)','','inherit','closed','closed','','360-revision-v1','','','2024-11-18 15:41:33','2024-11-18 15:41:33','',360,'https://zamman.ru/uncategorized/360-revision-v1/',0,'revision','',0),(787,1,'2024-11-18 15:42:52','2024-11-18 15:42:52','','С_1 (3)','','inherit','open','closed','','%d1%81_1-3-2','','','2024-11-18 15:42:52','2024-11-18 15:42:52','',382,'https://zamman.ru/app/uploads/2024/11/С_1-3.jpg',0,'attachment','image/jpeg',0),(788,1,'2024-11-18 15:43:00','2024-11-18 15:43:00','<p class=\"p1\">ООО «ЗАМАН» специализируется на<b> </b>производстве <b>установок дозирования химических реагентов (УДХР)</b>, блоков дозирования реагентов (БДР), а также и других комплексов различной сложности, предназначенных для автоматического введения химических реагентов в трубопроводные системы, которые используются для добычи, перекачки и переработки нефти и жидкостей.</p>\r\n<p class=\"p1\">БДР оборудованы всем необходимым для эффективного снижения вязкости, предотвращения образования солевых отложений и минимизации коррозии.</p>\r\n<p class=\"p1\">Каждый блок состоит из технологического и аппаратного отсеков, оснащенных насосом-дозатором, внутренними и внешними емкостями, трубопроводной обвязкой, вентиляцией и освещением. БДР также могут быть оборудованы автоматическими системами контроля и оповещения, обеспечивая бесперебойную работу.</p>\r\n<p class=\"p1\">Наше оборудование представлено в теплоизолированных блок-боксах или контейнерах. Конструкция соответствует стандартам безопасности.</p>\r\n<p class=\"p1\">Мы производим современные УДХР и БДР с качественным оборудованием и длительным гарантийным периодом, учитывая все требования клиента для идеального решения поставленных задач. Помимо этого, мы предлагаем варианты оборудования без блока-укрытия для его монтажа в существующее помещение клиента.</p>\r\n<p class=\"p1\">Обратитесь к нам, и мы поможем подобрать оптимальное решение для Вашего производства!</p>','Установки дозирования химических реагентов (УДХР)','','inherit','closed','closed','','382-revision-v1','','','2024-11-18 15:43:00','2024-11-18 15:43:00','',382,'https://zamman.ru/uncategorized/382-revision-v1/',0,'revision','',0),(789,1,'2024-11-18 15:43:41','2024-11-18 15:43:41','','С_1 (3)','','inherit','open','closed','','%d1%81_1-3-3','','','2024-11-18 15:43:41','2024-11-18 15:43:41','',382,'https://zamman.ru/app/uploads/2024/11/С_1-3-1.jpg',0,'attachment','image/jpeg',0),(790,1,'2024-11-18 15:44:00','2024-11-18 15:44:00','<p class=\"p1\">ООО «ЗАМАН» специализируется на<b> </b>производстве <b>установок дозирования химических реагентов (УДХР)</b>, блоков дозирования реагентов (БДР), а также и других комплексов различной сложности, предназначенных для автоматического введения химических реагентов в трубопроводные системы, которые используются для добычи, перекачки и переработки нефти и жидкостей.</p>\r\n<p class=\"p1\">БДР оборудованы всем необходимым для эффективного снижения вязкости, предотвращения образования солевых отложений и минимизации коррозии.</p>\r\n<p class=\"p1\">Каждый блок состоит из технологического и аппаратного отсеков, оснащенных насосом-дозатором, внутренними и внешними емкостями, трубопроводной обвязкой, вентиляцией и освещением. БДР также могут быть оборудованы автоматическими системами контроля и оповещения, обеспечивая бесперебойную работу.</p>\r\n<p class=\"p1\">Наше оборудование представлено в теплоизолированных блок-боксах или контейнерах. Конструкция соответствует стандартам безопасности.</p>\r\n<p class=\"p1\">Мы производим современные УДХР и БДР с качественным оборудованием и длительным гарантийным периодом, учитывая все требования клиента для идеального решения поставленных задач. Помимо этого, мы предлагаем варианты оборудования без блока-укрытия для его монтажа в существующее помещение клиента.</p>\r\n<p class=\"p1\">Обратитесь к нам, и мы поможем подобрать оптимальное решение для Вашего производства!</p>','Установки дозирования химических реагентов (УДХР)','','inherit','closed','closed','','382-revision-v1','','','2024-11-18 15:44:00','2024-11-18 15:44:00','',382,'https://zamman.ru/uncategorized/382-revision-v1/',0,'revision','',0),(791,1,'2024-11-18 15:44:54','2024-11-18 15:44:54','','Р†ІҐ®в®• ѓаЃ®ІҐЃ§бвҐ•≠≠Ѓ© °†Іл (9)','','inherit','open','closed','','%d1%80%e2%80%a0%d1%96%d2%91%d0%b2-%d0%b3%d0%b0%d0%b3%d1%96%d2%91%d0%b3%c2%a7%d0%b1%d0%b2%d2%91%e2%89%a0%e2%89%a0%d0%b3-%e2%80%a0','','','2024-11-18 15:44:54','2024-11-18 15:44:54','',611,'https://zamman.ru/app/uploads/2024/11/Р†ІҐ®в®•-ѓаЃ®ІҐЃ§бвҐ•≠≠Ѓ©-°†Іл-9.jpg',0,'attachment','image/jpeg',0),(792,1,'2024-11-18 15:44:54','2024-11-18 15:44:54','','Р†ІҐ®в®• ѓаЃ®ІҐЃ§бвҐ•≠≠Ѓ© °†Іл (8)','','inherit','open','closed','','%d1%80%e2%80%a0%d1%96%d2%91%d0%b2-%d0%b3%d0%b0%d0%b3%d1%96%d2%91%d0%b3%c2%a7%d0%b1%d0%b2%d2%91%e2%89%a0%e2%89%a0%d0%b3-%e2%80%a0-2','','','2024-11-18 15:44:54','2024-11-18 15:44:54','',611,'https://zamman.ru/app/uploads/2024/11/Р†ІҐ®в®•-ѓаЃ®ІҐЃ§бвҐ•≠≠Ѓ©-°†Іл-8.jpg',0,'attachment','image/jpeg',0),(793,1,'2024-11-18 15:44:54','2024-11-18 15:44:54','','Р†ІҐ®в®• ѓаЃ®ІҐЃ§бвҐ•≠≠Ѓ© °†Іл (7)','','inherit','open','closed','','%d1%80%e2%80%a0%d1%96%d2%91%d0%b2-%d0%b3%d0%b0%d0%b3%d1%96%d2%91%d0%b3%c2%a7%d0%b1%d0%b2%d2%91%e2%89%a0%e2%89%a0%d0%b3-%e2%80%a0-3','','','2024-11-18 15:44:54','2024-11-18 15:44:54','',611,'https://zamman.ru/app/uploads/2024/11/Р†ІҐ®в®•-ѓаЃ®ІҐЃ§бвҐ•≠≠Ѓ©-°†Іл-7.jpg',0,'attachment','image/jpeg',0),(794,1,'2024-11-18 15:44:55','2024-11-18 15:44:55','','Р†ІҐ®в®• ѓаЃ®ІҐЃ§бвҐ•≠≠Ѓ© °†Іл (6)','','in