03-10 13:20:16','',0,'https://zamman.ru/events/%d1%83%d0%b2%d0%b0%d0%b6%d0%b0%d0%b5%d0%bc%d1%8b%d0%b5-%d0%ba%d0%be%d0%bb%d0%bb%d0%b5%d0%b3%d0%b8-%d0%bf%d0%be%d0%b7%d0%b4%d1%80%d0%b0%d0%b2%d0%bb%d1%8f%d0%b5%d0%bc-%d0%b2%d0%b0%d1%81-%d1%81-%d0%b4/',0,'post','',0),(1003,0,'2024-12-27 14:54:06','2024-12-27 14:54:06','','U366Ws-2eE3UivvigaWTO23eLWYdegrCKVu7Wu8KWnFH7ep9gqkfDYysb8pGHut2-Me5QpO-wZeaf8rlJ85xcw2v','','inherit','open','closed','','u366ws-2ee3uivvigawto23elwydegrckvu7wu8kwnfh7ep9gqkfdyysb8pghut2-me5qpo-wzeaf8rlj85xcw2v','','','2024-12-27 14:54:06','2024-12-27 14:54:06','',1002,'https://zamman.ru/app/uploads/2024/12/U366Ws-2eE3UivvigaWTO23eLWYdegrCKVu7Wu8KWnFH7ep9gqkfDYysb8pGHut2-Me5QpO-wZeaf8rlJ85xcw2v.jpg',0,'attachment','image/jpeg',0),(1004,1,'2024-09-28 07:00:06','2024-09-28 07:00:06','28 сентября в России отмечается День директора – день, когда мы можем выразить признательность тем, кто ведет нас за собой.\r\n\r\nДорогой Михаил Валерьевич!\r\n\r\nОт всей души поздравляем Вас и выражаем искреннюю благодарность за Ваше нелегкое, но такое важное дело.\r\nВы не просто директор, Вы настоящий лидер, который умеет объединять людей, видеть в них потенциал и вдохновлять на свершения.\r\n\r\nИскренне благодарим Вас за ту теплоту и заботу, которые Вы проявляете к каждому из нас. Благодаря Вам мы становимся лучше, растем и достигаем результатов. Ваша преданность делу и твердое руководство являются для всех нас примером. Мы восхищаемся Вашим умением принимать непростые решения и создавать атмосферу, где царит уважение и взаимоподдержка.\r\n\r\nВ этот особенный день мы желаем Вам здоровья, профессиональных успехов и личного счастья! Пусть каждый день приносит вам удовлетворение от достигнутых целей и стремление к новым!\r\n\r\nС уважением,\r\nВаша команда ООО \"ЗАМАН\".','День директора','','publish','open','open','','28-%d1%81%d0%b5%d0%bd%d1%82%d1%8f%d0%b1%d1%80%d1%8f-%d0%b2-%d1%80%d0%be%d1%81%d1%81%d0%b8%d0%b8-%d0%be%d1%82%d0%bc%d0%b5%d1%87%d0%b0%d0%b5%d1%82%d1%81%d1%8f-%d0%b4%d0%b5%d0%bd%d1%8c-%d0%b4%d0%b8%d1%80','','','2025-03-10 11:36:10','2025-03-10 11:36:10','',0,'https://zamman.ru/events/28-%d1%81%d0%b5%d0%bd%d1%82%d1%8f%d0%b1%d1%80%d1%8f-%d0%b2-%d1%80%d0%be%d1%81%d1%81%d0%b8%d0%b8-%d0%be%d1%82%d0%bc%d0%b5%d1%87%d0%b0%d0%b5%d1%82%d1%81%d1%8f-%d0%b4%d0%b5%d0%bd%d1%8c-%d0%b4%d0%b8%d1%80/',0,'post','',0),(1005,0,'2024-12-27 14:54:06','2024-12-27 14:54:06','','TXLd1TPoY9pH51LruKnfmmMg1zs8KRrXNaeEqqJWIBhL2tFkmANMACjVUdfUw78Qu4r0DNgg0_KmbWUBDNnMG6gl','','inherit','open','closed','','txld1tpoy9ph51lruknfmmmg1zs8krrxnaeeqqjwibhl2tfkmanmacjvudfuw78qu4r0dngg0_kmbwubdnnmg6gl','','','2024-12-27 14:54:06','2024-12-27 14:54:06','',1004,'https://zamman.ru/app/uploads/2024/12/TXLd1TPoY9pH51LruKnfmmMg1zs8KRrXNaeEqqJWIBhL2tFkmANMACjVUdfUw78Qu4r0DNgg0_KmbWUBDNnMG6gl.jpg',0,'attachment','image/jpeg',0),(1006,1,'2024-09-27 18:45:06','2024-09-27 18:45:06','Сегодня, в преддверии праздника, мы с коллегами провели время вместе и отметили «День машиностроителя»?','День машиностроителя','','publish','open','open','','%d1%81%d0%b5%d0%b3%d0%be%d0%b4%d0%bd%d1%8f-%d0%b2-%d0%bf%d1%80%d0%b5%d0%b4%d0%b4%d0%b2%d0%b5%d1%80%d0%b8%d0%b8-%d0%bf%d1%80%d0%b0%d0%b7%d0%b4%d0%bd%d0%b8%d0%ba%d0%b0-%d0%bc%d1%8b-%d1%81-%d0%ba%d0%be','','','2025-03-10 11:36:49','2025-03-10 11:36:49','',0,'https://zamman.ru/events/%d1%81%d0%b5%d0%b3%d0%be%d0%b4%d0%bd%d1%8f-%d0%b2-%d0%bf%d1%80%d0%b5%d0%b4%d0%b4%d0%b2%d0%b5%d1%80%d0%b8%d0%b8-%d0%bf%d1%80%d0%b0%d0%b7%d0%b4%d0%bd%d0%b8%d0%ba%d0%b0-%d0%bc%d1%8b-%d1%81-%d0%ba%d0%be/',0,'post','',0),(1007,0,'2024-12-27 14:54:06','2024-12-27 14:54:06','','1e6DnF57XzAg-LamRcJXufGt_VDoF18nitl1geNj9MnwLxrirW8KWR-evgcqXB-b_rwuVkwZWqXSWSqFlGFmh-gJ','','inherit','open','closed','','1e6dnf57xzag-lamrcjxufgt_vdof18nitl1genj9mnwlxrirw8kwr-evgcqxb-b_rwuvkwzwqxswsqflgfmh-gj','','','2024-12-27 14:54:06','2024-12-27 14:54:06','',1006,'https://zamman.ru/app/uploads/2024/12/1e6DnF57XzAg-LamRcJXufGt_VDoF18nitl1geNj9MnwLxrirW8KWR-evgcqXB-b_rwuVkwZWqXSWSqFlGFmh-gJ.jpg',0,'attachment','image/jpeg',0),(1008,1,'2024-08-29 12:00:06','2024-08-29 12:00:06','28 августа 1965 года председатель Президиума Верховного Совета СССР Анастас Микоян подписал указ об установлении праздника «Всесоюзный день работников нефтяной и газовой промышленности», который стали отмечать ежегодно в первое воскресенье сентября.\r\n\r\n1 октября 1980 года, спустя 15 лет, этот день получил статус государственного праздника.\r\n\r\n??Интересные факты:\r\n\r\n1⃣ Первое в мире бурение нефтяной скважины проведено в 1846 году в поселке Биби-Эйбат рядом с Баку, входившем на то время в состав Российской империи.\r\n\r\n2⃣ Раньше бензин и другие виды топлива продавали в аптеках. Первая газобензиновая станция открылась в 1888 году в немецком городе Вислох.\r\n\r\n3⃣ Несмотря на то, что нефть называют черным золотом, она может иметь разные оттенки в зависимости от углеводородного состава — от черного до желтого.\r\n\r\n4⃣ Всего четыре капли нефти могут испортить 100 литров чистой питьевой воды.\r\n\r\n5⃣ В азербайджанском городе Нафталан некоторые клиники предлагают нефтяные ванны, которые, по слухам, помогают при артритах.\r\n\r\n6⃣ Три страны с крупнейшими запасами нефти: Венесуэла (303,8 млрд баррелей), Саудовская Аравия (297,5 млрд) и Канада (168,1 млрд). Россия занимает шестое место (107,8 млрд).\r\n\r\n7⃣ Ежедневно мировая промышленность потребляет около 84 миллионов баррелей нефти, что составляет примерно 13,3 млрд литров, а человечество использует нефти столько, сколько природа создает за 1500 лет.','Интересные факты о Дне работников нефтяной и газовой промышленности','','publish','open','open','','28-%d0%b0%d0%b2%d0%b3%d1%83%d1%81%d1%82%d0%b0-1965-%d0%b3%d0%be%d0%b4%d0%b0-%d0%bf%d1%80%d0%b5%d0%b4%d1%81%d0%b5%d0%b4%d0%b0%d1%82%d0%b5%d0%bb%d1%8c-%d0%bf%d1%80%d0%b5%d0%b7%d0%b8%d0%b4%d0%b8%d1%83','','','2025-03-10 11:41:10','2025-03-10 11:41:10','',0,'https://zamman.ru/events/28-%d0%b0%d0%b2%d0%b3%d1%83%d1%81%d1%82%d0%b0-1965-%d0%b3%d0%be%d0%b4%d0%b0-%d0%bf%d1%80%d0%b5%d0%b4%d1%81%d0%b5%d0%b4%d0%b0%d1%82%d0%b5%d0%bb%d1%8c-%d0%bf%d1%80%d0%b5%d0%b7%d0%b8%d0%b4%d0%b8%d1%83/',0,'post','',0),(1009,0,'2024-12-27 14:54:06','2024-12-27 14:54:06','','BT_2kCRdcogLMl2uQsdqQ8yfltKL8StItZ99I2V5Yd8AFDNgOXRaNEb6dAqsvQFfprHbA1CHodnkIbA4FJxD6_G0','','inherit','open','closed','','bt_2kcrdcoglml2uqsdqq8yfltkl8stitz99i2v5yd8afdngoxraneb6daqsvqffprhba1chodnkiba4fjxd6_g0','','','2024-12-27 14:54:06','2024-12-27 14:54:06','',1008,'https://zamman.ru/app/uploads/2024/12/BT_2kCRdcogLMl2uQsdqQ8yfltKL8StItZ99I2V5Yd8AFDNgOXRaNEb6dAqsvQFfprHbA1CHodnkIbA4FJxD6_G0.jpg',0,'attachment','image/jpeg',0),(1010,1,'2024-12-27 14:55:29','2024-12-27 14:55:29','Сегодня сотрудники Госавтоинспекции Республики Татарстан провели важное профилактическое мероприятие по безопасности дорожного движения. В ходе встречи была озвучена статистика аварийности на дорогах Альметьевского района и всей республики. Это мероприятие направлено на повышение осведомленности граждан и улучшение ситуации на наших дорогах. \r\n \r\nБерегите себя и соблюдайте правила дорожного движения!','Сегодня сотрудники Госавтоинспекции Республики Татарстан провели важное профилактическое мероприятие по...','','inherit','closed','closed','','999-revision-v1','','','2024-12-27 14:55:29','2024-12-27 14:55:29','',999,'https://zamman.ru/uncategorized/999-revision-v1/',0,'revision','',0),(1011,1,'2024-12-27 14:56:36','2024-12-27 14:56:36','Уважаемые коллеги!\r\n\r\nПоздравляем вас с Днем машиностроителя!\r\n\r\nСпасибо за ваше мастерство, профессионализм и трудолюбие, которые вносят значительный вклад в развитие отечественного машиностроения.\r\n\r\nЖелаем новых свершений, высоких достижений и успешной реализации всех намеченных планов.\r\n\r\nКоллектив ООО “ЗАМАН”','Уважаемые коллеги! Поздравляем вас с Днем машиностроителя! Спасибо за ваше...','','inherit','closed','closed','','1002-revision-v1','','','2024-12-27 14:56:36','2024-12-27 14:56:36','',1002,'https://zamman.ru/uncategorized/1002-revision-v1/',0,'revision','',0),(1012,1,'2024-12-27 14:56:44','2024-12-27 14:56:44','28 сентября в России отмечается День директора – день, когда мы можем выразить признательность тем, кто ведет нас за собой.\r\n\r\nДорогой Михаил Валерьевич!\r\n\r\nОт всей души поздравляем Вас и выражаем искреннюю благодарность за Ваше нелегкое, но такое важное дело.\r\nВы не просто директор, Вы настоящий лидер, который умеет объединять людей, видеть в них потенциал и вдохновлять на свершения.\r\n\r\nИскренне благодарим Вас за ту теплоту и заботу, которые Вы проявляете к каждому из нас. Благодаря Вам мы становимся лучше, растем и достигаем результатов. Ваша преданность делу и твердое руководство являются для всех нас примером. Мы восхищаемся Вашим умением принимать непростые решения и создавать атмосферу, где царит уважение и взаимоподдержка.\r\n\r\nВ этот особенный день мы желаем Вам здоровья, профессиональных успехов и личного счастья! Пусть каждый день приносит вам удовлетворение от достигнутых целей и стремление к новым!\r\n\r\nС уважением,\r\nВаша команда ООО \"ЗАМАН\".','28 сентября в России отмечается День директора – день, когда...','','inherit','closed','closed','','1004-revision-v1','','','2024-12-27 14:56:44','2024-12-27 14:56:44','',1004,'https://zamman.ru/uncategorized/1004-revision-v1/',0,'revision','',0),(1013,1,'2024-12-27 14:56:50','2024-12-27 14:56:50','Сегодня, в преддверии праздника, мы с коллегами провели время вместе и отметили «День машиностроителя»?','Сегодня, в преддверии праздника, мы с коллегами провели время вместе...','','inherit','closed','closed','','1006-revision-v1','','','2024-12-27 14:56:50','2024-12-27 14:56:50','',1006,'https://zamman.ru/uncategorized/1006-revision-v1/',0,'revision','',0),(1014,1,'2024-12-27 14:56:56','2024-12-27 14:56:56','28 августа 1965 года председатель Президиума Верховного Совета СССР Анастас Микоян подписал указ об установлении праздника «Всесоюзный день работников нефтяной и газовой промышленности», который стали отмечать ежегодно в первое воскресенье сентября.\r\n\r\n1 октября 1980 года, спустя 15 лет, этот день получил статус государственного праздника.\r\n\r\n??Интересные факты:\r\n\r\n1⃣ Первое в мире бурение нефтяной скважины проведено в 1846 году в поселке Биби-Эйбат рядом с Баку, входившем на то время в состав Российской империи.\r\n\r\n2⃣ Раньше бензин и другие виды топлива продавали в аптеках. Первая газобензиновая станция открылась в 1888 году в немецком городе Вислох.\r\n\r\n3⃣ Несмотря на то, что нефть называют черным золотом, она может иметь разные оттенки в зависимости от углеводородного состава — от черного до желтого.\r\n\r\n4⃣ Всего четыре капли нефти могут испортить 100 литров чистой питьевой воды.\r\n\r\n5⃣ В азербайджанском городе Нафталан некоторые клиники предлагают нефтяные ванны, которые, по слухам, помогают при артритах.\r\n\r\n6⃣ Три страны с крупнейшими запасами нефти: Венесуэла (303,8 млрд баррелей), Саудовская Аравия (297,5 млрд) и Канада (168,1 млрд). Россия занимает шестое место (107,8 млрд).\r\n\r\n7⃣ Ежедневно мировая промышленность потребляет около 84 миллионов баррелей нефти, что составляет примерно 13,3 млрд литров, а человечество использует нефти столько, сколько природа создает за 1500 лет.','28 августа 1965 года председатель Президиума Верховного Совета СССР Анастас...','','inherit','closed','closed','','1008-revision-v1','','','2024-12-27 14:56:56','2024-12-27 14:56:56','',1008,'https://zamman.ru/uncategorized/1008-revision-v1/',0,'revision','',0),(1015,1,'2024-12-27 14:57:03','2024-12-27 14:57:03','Вчера вечером наша команда ООО \"ЗАМАН\" решила внести нотку адреналина в повседневную рабочую жизнь и отправилась на картинг! ??\r\n\r\nМы провели настоящие соревнования среди сотрудников, где определили победителей, занявших 1, 2 и 3 места! ??? Этот вечер подарил нам незабываемые впечатления и сплотил команду еще больше. Спасибо всем участникам за отличное настроение и дух соревнования!?\r\n\r\nС нетерпением ждем следующей встречи, а пока - делимся моментами нашего чемпионата! ?','Вчера вечером наша команда ООО \"ЗАМАН\" решила внести нотку адреналина...','','inherit','closed','closed','','988-revision-v1','','','2024-12-27 14:57:03','2024-12-27 14:57:03','',988,'https://zamman.ru/uncategorized/988-revision-v1/',0,'revision','',0),(1017,1,'2025-01-20 07:33:18','2025-01-20 07:33:18','','photo_2025-01-20 10.32.58','','inherit','open','closed','','photo_2025-01-20-10-32-58','','','2025-01-20 07:33:18','2025-01-20 07:33:18','',988,'https://zamman.ru/app/uploads/2024/12/photo_2025-01-20-10.32.58.jpeg',0,'attachment','image/jpeg',0),(1019,1,'2025-01-20 07:42:37','2025-01-20 07:42:37','','vkclips_20250120104131','','inherit','open','closed','','vkclips_20250120104131','','','2025-01-20 07:42:37','2025-01-20 07:42:37','',0,'https://zamman.ru/app/uploads/2024/12/vkclips_20250120104131.mp4',0,'attachment','video/mp4',0),(1020,1,'2025-01-20 07:45:12','2025-01-20 07:45:12','','photo_2025-01-20 10.44.42','','inherit','open','closed','','photo_2025-01-20-10-44-42','','','2025-01-20 07:45:12','2025-01-20 07:45:12','',0,'https://zamman.ru/app/uploads/2024/12/photo_2025-01-20-10.44.42.jpeg',0,'attachment','image/jpeg',0),(1022,1,'2025-01-20 07:51:45','2025-01-20 07:51:45','','photo_2025-01-20 10.51.33','','inherit','open','closed','','photo_2025-01-20-10-51-33','','','2025-01-20 07:51:45','2025-01-20 07:51:45','',1004,'https://zamman.ru/app/uploads/2024/12/photo_2025-01-20-10.51.33.jpeg',0,'attachment','image/jpeg',0),(1023,1,'2025-01-20 07:54:55','2025-01-20 07:54:55','Сегодня сотрудники Госавтоинспекции Республики Татарстан провели важное профилактическое мероприятие по безопасности дорожного движения. В ходе встречи была озвучена статистика аварийности на дорогах Альметьевского района и всей республики. Это мероприятие направлено на повышение осведомленности граждан и улучшение ситуации на наших дорогах.\r\n\r\nБерегите себя и соблюдайте правила дорожного движения!','Сегодня сотрудники Госавтоинспекции Республики Татарстан провели важное профилактическое мероприятие по...','','inherit','closed','closed','','999-revision-v1','','','2025-01-20 07:54:55','2025-01-20 07:54:55','',999,'https://zamman.ru/uncategorized/999-revision-v1/',0,'revision','',0),(1058,1,'2025-01-20 08:50:54','2025-01-20 08:50:54','<!-- wp:paragraph -->\n<p>Welcome to WordPress. This is your first post. Edit or delete it, then start writing!</p>\n<!-- /wp:paragraph -->','Hello world!','','inherit','closed','closed','','1-revision-v1','','','2025-01-20 08:50:54','2025-01-20 08:50:54','',1,'https://zamman.ru/uncategorized/1-revision-v1/',0,'revision','',0),(1059,1,'2025-01-21 14:03:06','2025-01-21 14:03:06','','Карта партнера','','publish','closed','closed','','partner-card','','','2025-09-26 08:33:52','2025-09-26 08:33:52','',0,'https://zamman.ru/?page_id=1059',0,'page','',0),(1060,1,'2025-01-21 14:03:06','2025-01-21 14:03:06','','Карта партнера','','inherit','closed','closed','','1059-revision-v1','','','2025-01-21 14:03:06','2025-01-21 14:03:06','',1059,'https://zamman.ru/uncategorized/1059-revision-v1/',0,'revision','',0),(1061,1,'2025-01-22 09:28:22','2025-01-22 09:28:22','','Карта партнера ООО ЗАМАН 2024','','inherit','open','closed','','%d0%ba%d0%b0%d1%80%d1%82%d0%b0-%d0%bf%d0%b0%d1%80%d1%82%d0%bd%d0%b5%d1%80%d0%b0-%d0%be%d0%be%d0%be-%d0%b7%d0%b0%d0%bc%d0%b0%d0%bd-2024','','','2025-01-22 09:28:22','2025-01-22 09:28:22','',0,'https://zamman.ru/app/uploads/2025/01/Карта-партнера-ООО-ЗАМАН-2024.pdf',0,'attachment','application/pdf',0),(1062,1,'2025-01-22 09:28:59','2025-01-22 09:28:59','','partner-card','','inherit','open','closed','','partner-card-2','','','2025-01-22 09:28:59','2025-01-22 09:28:59','',0,'https://zamman.ru/app/uploads/2025/01/partner-card.pdf',0,'attachment','application/pdf',0),(1064,1,'2025-01-28 12:25:56','2025-01-28 12:25:56','','ZAMMAN jpg инверсия','','inherit','open','closed','','zamman-jpg-%d0%b8%d0%bd%d0%b2%d0%b5%d1%80%d1%81%d0%b8%d1%8f','','','2025-01-28 12:25:56','2025-01-28 12:25:56','',0,'https://zamman.ru/app/uploads/2025/01/ZAMMAN-jpg-инверсия.jpg',0,'attachment','image/jpeg',0),(1068,1,'2025-01-30 18:45:48','2025-01-30 18:45:48','Доброго вечера, друзья!\r\n\r\nПервый пост в этом году мы решили посвятить интересным новостям.\r\n\r\nСегодня у нас прошли соревнования по настольному теннису среди сотрудников ООО «ЗАМАН». Мы были рады видеть, как наши коллеги демонстрируют свои навыки и соревнуются за звание лучшего игрока.\r\n\r\nДелимся с вами яркими моментами этого события!','Соревнования по настольному теннису','','publish','open','open','','%d0%b4%d0%be%d0%b1%d1%80%d0%be%d0%b3%d0%be-%d0%b2%d0%b5%d1%87%d0%b5%d1%80%d0%b0-%d0%b4%d1%80%d1%83%d0%b7%d1%8c%d1%8f-%d0%bf%d0%b5%d1%80%d0%b2%d1%8b%d0%b9-%d0%bf%d0%be%d1%81%d1%82-%d0%b2-%d1%8d%d1%82','','','2025-03-10 11:28:19','2025-03-10 11:28:19','',0,'https://zamman.ru/events/%d0%b4%d0%be%d0%b1%d1%80%d0%be%d0%b3%d0%be-%d0%b2%d0%b5%d1%87%d0%b5%d1%80%d0%b0-%d0%b4%d1%80%d1%83%d0%b7%d1%8c%d1%8f-%d0%bf%d0%b5%d1%80%d0%b2%d1%8b%d0%b9-%d0%bf%d0%be%d1%81%d1%82-%d0%b2-%d1%8d%d1%82/',0,'post','',0),(1069,0,'2025-02-03 07:26:48','2025-02-03 07:26:48','','9Y02A5KOWkxwgz1g__QMfE7pQiA5mEw6NB_g123Whh28CwLeQO9WhbyJduWnsn5y1MlwtN88Xbt0kXkAv5CRM-eV','','inherit','open','closed','','9y02a5kowkxwgz1g__qmfe7pqia5mew6nb_g123whh28cwleqo9whbyjduwnsn5y1mlwtn88xbt0kxkav5crm-ev','','','2025-02-03 07:26:48','2025-02-03 07:26:48','',1068,'https://zamman.ru/app/uploads/2025/02/9Y02A5KOWkxwgz1g__QMfE7pQiA5mEw6NB_g123Whh28CwLeQO9WhbyJduWnsn5y1MlwtN88Xbt0kXkAv5CRM-eV.jpg',0,'attachment','image/jpeg',0),(1070,0,'2025-02-03 07:26:48','2025-02-03 07:26:48','','4soLENW-V38hrirhgl4iX1H4D_rKRDnui_gTpg0ysF6-3P5ue_LyhkyIa0re3cRB9PkqAswduo-7uQo2bwfQGTX0','','inherit','open','closed','','4solenw-v38hrirhgl4ix1h4d_rkrdnui_gtpg0ysf6-3p5ue_lyhkyia0re3crb9pkqaswduo-7uqo2bwfqgtx0','','','2025-02-03 07:26:48','2025-02-03 07:26:48','',1068,'https://zamman.ru/app/uploads/2025/02/4soLENW-V38hrirhgl4iX1H4D_rKRDnui_gTpg0ysF6-3P5ue_LyhkyIa0re3cRB9PkqAswduo-7uQo2bwfQG