ства и добра.\r\n\r\nМы убеждены: счастливые дети — это счастливые семьи, а крепкие семьи — основа сильного коллектива. Забота о подрастающем поколении — неотъемлемая часть корпоративной культуры нашей компании.\r\n\r\nПусть каждый ребенок чувствует себя защищенным, любимым и окруженным вниманием!','Накануне Международного дня защиты детей мы подарили детям сотрудников ООО «ЗАМАН» праздник, полный волшебства и добра.','','publish','open','open','','%d0%b4%d0%b5%d1%82%d1%81%d0%ba%d0%b8%d0%b9-%d1%81%d0%bc%d0%b5%d1%85-%d1%81%d0%b8%d1%8f%d1%8e%d1%89%d0%b8%d0%b5-%d0%b3%d0%bb%d0%b0%d0%b7%d0%b0-%d0%b8-%d0%b1%d0%b5%d0%b7%d0%b7%d0%b0%d0%b1%d0%be%d1%82','','','2025-06-30 06:11:41','2025-06-30 06:11:41','',0,'https://zamman.ru/events/%d0%b4%d0%b5%d1%82%d1%81%d0%ba%d0%b8%d0%b9-%d1%81%d0%bc%d0%b5%d1%85-%d1%81%d0%b8%d1%8f%d1%8e%d1%89%d0%b8%d0%b5-%d0%b3%d0%bb%d0%b0%d0%b7%d0%b0-%d0%b8-%d0%b1%d0%b5%d0%b7%d0%b7%d0%b0%d0%b1%d0%be%d1%82/',0,'post','',0),(1352,0,'2025-06-03 14:54:43','2025-06-03 14:54:43','','lbtJBgqHc7sr1c9DulOu6r2ELVQkOEDbiLdZn1AfUHLaTzuylHl52S9cOAxMLf_Z8WpHCPHbWBQ49RMtpKuaozhY','','inherit','open','closed','','lbtjbgqhc7sr1c9dulou6r2elvqkoedbildzn1afuhlatzuylhl52s9coaxmlf_z8wphcphbwbq49rmtpkuaozhy','','','2025-06-03 14:54:43','2025-06-03 14:54:43','',1351,'https://zamman.ru/app/uploads/2025/06/lbtJBgqHc7sr1c9DulOu6r2ELVQkOEDbiLdZn1AfUHLaTzuylHl52S9cOAxMLf_Z8WpHCPHbWBQ49RMtpKuaozhY.jpg',0,'attachment','image/jpeg',0),(1353,0,'2025-06-03 14:54:43','2025-06-03 14:54:43','','H5SOTx2x7Tl5oQOTkWCMnqp-sZ-l1lH_iqeZX9BT954wNasP7wpj5n94bsBzxkpQ6UJgBBSMsMRV7DSmDW1BawL0','','inherit','open','closed','','h5sotx2x7tl5oqotkwcmnqp-sz-l1lh_iqezx9bt954wnasp7wpj5n94bsbzxkpq6ujgbbsmsmrv7dsmdw1bawl0','','','2025-06-03 14:54:43','2025-06-03 14:54:43','',1351,'https://zamman.ru/app/uploads/2025/06/H5SOTx2x7Tl5oQOTkWCMnqp-sZ-l1lH_iqeZX9BT954wNasP7wpj5n94bsBzxkpQ6UJgBBSMsMRV7DSmDW1BawL0.jpg',0,'attachment','image/jpeg',0),(1354,0,'2025-06-03 14:54:43','2025-06-03 14:54:43','','qiigSe0x0XYf9f