','closed','','unqjt2na6bnx06i-fou8posj5ne32s3d8dlq-i2giqfau6wtggpj648ddp2ldakgesyxxnlfmunj_g9bx4bo8xcv','','','2026-05-09 08:53:25','2026-05-09 05:53:25','',2146,'https://zamman.ru/app/uploads/2026/05/uNQjT2Na6bNX06i-FOu8pOSJ5NE32s3d8DLq-I2GiqfAu6WtggPj648dDP2LdakgEsyXxNlfMUnj_G9Bx4bO8xCv.jpg',0,'attachment','image/jpeg',0),(2155,0,'2026-05-09 08:53:25','2026-05-09 05:53:25','','TTTJNGhov5cgm5ffENsBbgURSZpOeiXU7lzA2kGGgICsGPXXqYkmJUsUM0SVwyrroTBJ8GL3c5ujIw4ORDDlEUgn','','inherit','open','closed','','tttjnghov5cgm5ffensbbgurszpoeixu7lza2kgggicsgpxxqykmjusum0svwyrrotbj8gl3c5ujiw4orddleugn','','','2026-05-09 08:53:25','2026-05-09 05:53:25','',2146,'https://zamman.ru/app/uploads/2026/05/TTTJNGhov5cgm5ffENsBbgURSZpOeiXU7lzA2kGGgICsGPXXqYkmJUsUM0SVwyrroTBJ8GL3c5ujIw4ORDDlEUgn.jpg',0,'attachment','image/jpeg',0),(2156,0,'2026-05-09 10:54:39','2026-05-09 07:54:39','Вчера наш коллектив в преддверии 9 Мая провёл митинг, посвящённый Дню Победы. \n \nВ ходе мероприятия говорили о значении этого великого праздника, о цене мира и важности сохранения исторической памяти. После торжественной части исполнили военные песни, а завершили митинг солдатской кашей, приготовленной силами коллектива. \n \nТакже, не изменяя своим традициям, подготовили подарки для детей войны — родственников наших сотрудников. Сердечно поздравили: \n• Касимову Раису Георгиевну (83 года), \n• Тишанькину Анну Матвеевну (90 лет), \n• Евстигнееву Миннур Хабибрасулловну (81 год), \n• Магданова Давлетгарая Саетзадовича (85 лет), \n• Нуртдинову Миннурый Гаптракиповну (87 лет). \n \nЖелаем им крепкого здоровья, долголетия, заботы и тепла близких!','Вчера наш коллектив в преддверии 9 Мая провёл митинг, посвящённый...','','publish','open','open','','%d0%b2%d1%87%d0%b5%d1%80%d0%b0-%d0%bd%d0%b0%d1%88-%d0%ba%d0%be%d0%bb%d0%bb%d0%b5%d0%ba%d1%82%d0%b8%d0%b2-%d0%b2-%d0%bf%d1%80%d0%b5%d0%b4%d0%b4%d0%b2%d0%b5%d1%80%d0%b8%d0%b8-9-%d0%bc%d0%b0%d1%8f-%d0%bf','','','2026-05-09 10:54:39','2026-05-09 07:54:39','',0,'https://zamman.ru/events/%d0%b2%d1%87%d0%b5%d1%80%d0%b0-%d0%bd%d0%b0%d1%88-%d0%ba%d0%be%d0%bb%d0%bb%d0%b5%d0%ba%d1%82%d0%b8%d0%b2-%d0%b2-%d0%bf%d1%80%d0%b5%d0%b4%d0%b4%d0%b2%d0%b5%d1%80%d0%b8%d0%b8-9-%d0%bc%d0%b0%d1%8f-%d0%bf/',0,'post','',0),(2157,0,'2026-05-09 10:54:40','2026-05-09 07:54:40','','Q3wHopE6KXf7IavOA6JI4JDJr8PRswqnLChmPvpqBjD3ruWOR1vT3AQpSq8G4qo4RR3lUt10Zojwilzw74nWmjZn','','inherit','open','closed','','q3whope6kxf7iavoa6ji4jdjr8prswqnlchmpvpqbjd3ruwor1vt3aqpsq8g4qo4rr3lut10zojwilzw74nwmjzn','','','2026-05-09 10:54:40','2026-05-09 07:54:40','',2156,'https://zamman.ru/app/uploads/2026/05/Q3wHopE6KXf7IavOA6JI4JDJr8PRswqnLChmPvpqBjD3ruWOR1vT3AQpSq8G4qo4RR3lUt10Zojwilzw74nWmjZn.jpg',0,'attachment','image/jpeg',0),(2158,0,'2026-05-09 10:54:41','2026-05-09 07:54:41','','mvIIyBflY0AR_3S1OxANAtx83fZ-i0xpdX0v2oeSVtysm5jzxULPLfQzuY5sa8CDn3GelwSRtIUcAsgiZJO3AkyE','','inherit','open','closed','','mviiybfly0ar_3s1oxanatx83fz-i0xpdx0v2oesvtysm5jzxulplfqzuy5sa8cdn3gelwsrtiucasgizjo3akye','','','2026-05-09 10:54:41','2026-05-09 07:54:41','',2156,'https://zamman.ru/app/uploads/2026/05/mvIIyBflY0AR_3S1OxANAtx83fZ-i0xpdX0v2oeSVtysm5jzxULPLfQzuY5sa8CDn3GelwSRtIUcAsgiZJO3AkyE.jpg',0,'attachment','image/jpeg',0),(2159,0,'2026-05-09 10:54:42','2026-05-09 07:54:42','','oNo_GAw7lfTK6qFo1eGRxmRnBLKdNlHcbBqqEew2Tp-S9HNZJjHu1M1YvslRe39WuN1serGErknI2Gsl4UxxmpBU','','inherit','open','closed','','ono_gaw7lftk6qfo1egrxmrnblkdnlhcbbqqeew2tp-s9hnzjjhu1m1yvslre39wun1sergerkni2gsl4uxxmpbu','','','2026-05-09 10:54:42','2026-05-09 07:54:42','',2156,'https://zamman.ru/app/uploads/2026/05/oNo_GAw7lfTK6qFo1eGRxmRnBLKdNlHcbBqqEew2Tp-S9HNZJjHu1M1YvslRe39WuN1serGErknI2Gsl4UxxmpBU.jpg',0,'attachment','image/jpeg',0),(2160,0,'2026-05-09 10:54:43','2026-05-09 07:54:43','','BURAgJjdgIMRE2L8eb-bu1LGivScTLnlUHqCYcC2bSmvvvMF9aw8o49z06bXEqm9UmVzRjEGNmplUCFAzgl7XbKS','','inherit','open','closed','','buragjjdgimre2l8eb-bu1lgivsctlnluhqcycc2bsmvvvmf9aw8o49z06bxeqm9umvzrjegnmplucfazgl7xbks','','','2026-05-09 10:54:43','