городе Богородицк Тульской области...','','publish','open','open','','%d0%b4%d0%b5%d0%bb%d0%b5%d0%b3%d0%b0%d1%86%d0%b8%d1%8f-%d0%b7%d0%b0%d0%bc%d0%b0%d0%bd-%d0%bf%d0%be%d1%81%d0%b5%d1%82%d0%b8%d0%bb%d0%b0-%d0%b7%d0%b0%d0%b2%d0%be%d0%b4-%e2%84%96423','','','2026-05-15 15:54:26','2026-05-15 12:54:26','',0,'https://zamman.ru/events/%d0%b4%d0%b5%d0%bb%d0%b5%d0%b3%d0%b0%d1%86%d0%b8%d1%8f-%d0%b7%d0%b0%d0%bc%d0%b0%d0%bd-%d0%bf%d0%be%d1%81%d0%b5%d1%82%d0%b8%d0%bb%d0%b0-%d0%b7%d0%b0%d0%b2%d0%be%d0%b4-%e2%84%96423/',0,'post','',0),(2171,0,'2026-05-15 15:54:26','2026-05-15 12:54:26','','dsiB7QEPSxWMc6i6w78MgHGhaG1GEdj-xuaiXC1zq2hsAp08jv1OmoXh_2zI8_OfzRbDCXapUkd1iFISjC8RF08y','','inherit','open','closed','','dsib7qepsxwmc6i6w78mghghag1gedj-xuaixc1zq2hsap08jv1omoxh_2zi8_ofzrbdcxapukd1ifisjc8rf08y','','','2026-05-15 15:54:26','2026-05-15 12:54:26','',2170,'https://zamman.ru/app/uploads/2026/05/dsiB7QEPSxWMc6i6w78MgHGhaG1GEdj-xuaiXC1zq2hsAp08jv1OmoXh_2zI8_OfzRbDCXapUkd1iFISjC8RF08y.jpg',0,'attachment','image/jpeg',0),(2172,0,'2026-05-15 15:54:27','2026-05-15 12:54:27','','rNv36Rd-iUCcCaghdBrFaZZ7ij2TDn276m6QVcKUS6c4ZapXYoUx_oN2FT-ULVsfh2WwztsZWEGQl5iR7N3tnNv','','inherit','open','closed','','rnv36rd-iucccaghdbrfazz7ij2tdn276m6qvckus6c4zapxyoux_on2ft-ulvsfh2wwztszwegql5ir7n3tnnv','','','2026-05-15 15:54:27','2026-05-15 12:54:27','',2170,'https://zamman.ru/app/uploads/2026/05/rNv36Rd-iUCcCaghdBrFaZZ7ij2TDn276m6QVcKUS6c4ZapXYoUx_oN2FT-ULVsfh2WwztsZWEGQl5iR7N3tnNv.jpg',0,'attachment','image/jpeg',0),(2173,0,'2026-05-15 15:54:27','2026-05-15 12:54:27','','4YQrWRkuSSl3Jf1ZsG7wc97XsG2eQ3hbutkth88R4QUlnhM8BckIl9nQm47y3LHvIgnnm2I2f4AOZ4oQP-okdzlT','','inherit','open','closed','','4yqrwrkussl3jf1zsg7wc97xsg2eq3hbutkth88r4qulnhm8bckil9nqm47y3lhvignnm2i2f4aoz4oqp-okdzlt','','','2026-05-15 15:54:27','2026-05-15 12:54:27','',2170,'https://zamman.ru/app/uploads/2026/05/4YQrWRkuSSl3Jf1ZsG7wc97XsG2eQ3hbutkth88R4QUlnhM8BckIl9nQm47y3LHvIgnnm2I2f4AOZ4oQP-okdzlT.jpg',0,'attachment','image/jpeg',0),(21